const API='dispatch_next_api.php';let state={date:localDateString(),search:'',users:[],data:null,me:null,currentDetail:null,mode:'personal',editMultiGroupId:null,scope:currentTableScope(),mobileView:localStorage.dispatch_next_mobile_view||'card',columns:[],editColumns:null,colorPrefs:{},editColorPrefs:null,saveTimers:{},emptyDeleteTimers:{},dragRow:null,newRows:{},recentCreated:{},recentCreateFallback:null,firstOpenMarked:{},localCellEdits:{},cellSaveStatus:{},styleCell:null,focusFilter:'',selectedTasks:new Set(),groupPopover:{taskId:null,anchor:null,data:null},detailTab:'detail',detailSaveStatus:{},pendingRender:false,noticeFilter:'pending_all',noticeSearch:'',noticePage:1,noticeCenterData:null,selectedNoticeId:'',noticeRules:{},peopleFilter:{personal:[],dispatch:[]},peopleFilterOpen:'',filters:{personal:{status:[],priority:[],overdue:false,collapsed:false},dispatch:{status:[],priority:[],overdue:false,collapsed:false}},lastSilentSync:0,lastVersionCheck:0,lastNoticeSync:0,lastOnlineSync:0,syncVersion:'',versionCheckRunning:false,ticker:null,resizeObserver:null,layoutWatcher:null,layoutSignature:''};
const defaultColumns=[['row_handle','','handle'],['complete','完成','complete'],['priority','优先级','select'],['title','任务标题','text'],['project','项目','textarea'],['due_at','截止日期','datetime'],['assigned_to','负责人','user'],['dispatch_mode','方式','mode'],['creator_name','派工来自','readonly'],['actions','操作','actions']];
function $(s,r=document){return r.querySelector(s)}function $all(s,r=document){return Array.from(r.querySelectorAll(s))}
function esc(v){return String(v??'').replace(/[&<>"']/g,s=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[s]))}
function formatFileSize(v){let n=Number(v||0);if(!n)return '0B';let units=['B','KB','MB','GB'],i=0;while(n>=1024&&i<units.length-1){n/=1024;i++}return (i?n.toFixed(n>=10?0:1):String(Math.round(n)))+units[i]}
function toast(msg){const n=$('#toast');n.textContent=msg;n.classList.add('show');clearTimeout(n.t);n.t=setTimeout(()=>n.classList.remove('show'),1800)}
async function api(action,data={},file){let opt={method:'POST',credentials:'same-origin'};if(file){let fd=new FormData();fd.set('action',action);Object.entries(data).forEach(([k,v])=>fd.set(k,v));fd.set('file',file);opt.body=fd}else{opt.headers={'Content-Type':'application/json'};opt.body=JSON.stringify(Object.assign({action},data))}let r=await fetch(API,opt);let j=await r.json().catch(()=>({ok:false,error:'接口返回异常'}));if(!j.ok)throw new Error(j.error||'操作失败');return j.data}
function localDateString(d=new Date()){let pad=n=>String(n).padStart(2,'0');return d.getFullYear()+'-'+pad(d.getMonth()+1)+'-'+pad(d.getDate())}
function today(){return localDateString()}
function isLandscapeScreen(){return !!(window.matchMedia&&window.matchMedia('(orientation: landscape)').matches)}
function currentTableScope(){let w=window.innerWidth||document.documentElement.clientWidth||0;if(w<=920&&isLandscapeScreen())return 'mobile_landscape';if(w<760)return 'mobile';return 'desktop'}
function isMobileLandscapeScope(){return state.scope==='mobile_landscape'||((window.innerWidth||0)<=920&&isLandscapeScreen())}
function setDark(on){document.body.classList.toggle('dark',on);localStorage.dispatch_next_dark=on?'1':'0';$('#darkBtn').textContent='暗黑：'+(on?'开':'关')}
