function bind(){document.body.addEventListener('click',async e=>{if(e.target.closest('[data-batch-select]'))return;let taskMail=e.target.closest('[data-task-mail-body]');if(taskMail){openDispatchTaskMailBodyPreview(taskMail.dataset.taskMailBody);e.preventDefault();e.stopPropagation();return}let mobileMenu=e.target.closest('[data-mobile-menu]');if(mobileMenu){toggleMobileActionMenu(mobileMenu);e.preventDefault();e.stopPropagation();return}let rowMobileMenu=e.target.closest('[data-mobile-row-menu]');if(rowMobileMenu){toggleMobileRowActionMenu(rowMobileMenu);e.preventDefault();e.stopPropagation();return}let transfer=e.target.closest('[data-transfer]');if(transfer){openTransferDialog(transfer.dataset.transfer);e.preventDefault();e.stopPropagation();return}let viewTransfer=e.target.closest('[data-view-transfer]');if(viewTransfer){openTransferTarget(viewTransfer.dataset.viewTransfer);e.preventDefault();e.stopPropagation();return}let restoreTransfer=e.target.closest('[data-restore-transfer]');if(restoreTransfer){restorePersonalTransfer(restoreTransfer.dataset.restoreTransfer);e.preventDefault();e.stopPropagation();return}let copy=e.target.closest('[data-copy-task-link]');if(copy){copyTaskLink(copy.dataset.copyTaskLink);e.preventDefault();e.stopPropagation();return}let projectToggle=e.target.closest('[data-mobile-project-toggle]');if(projectToggle){toggleMobileProject(projectToggle);e.preventDefault();e.stopPropagation();return}let editMulti=e.target.closest('[data-edit-multi]');if(editMulti){await openMultiEdit(editMulti.dataset.editMulti,editMulti.dataset.editSource||'');e.preventDefault();e.stopPropagation();return}let groupBtn=e.target.closest('[data-group-members]');if(groupBtn){await toggleGroupMemberPopover(groupBtn);return}let batch=e.target.closest('[data-batch-action]');if(batch){handleBatchAction(batch.dataset.batchAction);return}let more=e.target.closest('[data-more-settings]');if(more){$('#dispatchMoreSettings')?.classList.toggle('open');e.stopPropagation();ret