function toggleFilterPanel(type){let panel=document.querySelector(`[data-filter-panel="${type}"]`);if(!panel)return;document.querySelectorAll('.peopleFilterPanel.show').forEach(p=>{if(p!==panel)p.classList.remove('show')});panel.classList.toggle('show');if(type==='personal'||type==='dispatch')state.peopleFilterOpen=panel.classList.contains('show')?type:''}
