function togglePersonFilter(type,id){let s=String(id);let list=state.peopleFilter[type]||[];state.peopleFilter[type]=list.includes(s)?list.filter(v=>v!==s):list.concat([s]);state.peopleFilterOpen=type;savePeopleFilterPrefs();renderPeopleFilter(type);load()}
function clearPersonFilter(type){state.peopleFilter[type]=[];state.peopleFilterOpen=type;savePeopleFilterPrefs();renderPeopleFilter(type);load()}
function updateStatusClock(){let d=new Date();let pad=n=>String(n).padStart(2,'0');let clock=$('[data-status-clock]'),date=$('[data-status-date]');if(clock)clock.textContent=pad(d.getHours())+':'+pad(d.getMinutes())+':'+pad(d.getSeconds());if(date)date.textContent=d.getFullYear()+'-'+pad(d.getMonth()+1)+'-'+pad(d.getDate());renderWorldTimes()}
function worldTimeZones(){return [['本地/北京','Asia/Shanghai','GMT+8'],['纽约','America/New_York','US Eastern'],['伦敦','Europe/London','London'],['柏林','Europe/Berlin','Berlin'],['新加坡','Asia/Singapore','GMT+8']]}
function zoneTime(zone){try{return new Intl.DateTimeFormat('zh-CN',{timeZone:zone,hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false,month:'2-digit',day:'2-digit'}).format(new Date())}catch(e){return '--:--'}}
function renderWorldTimes(){let box=$('#worldTimeMenu');if(!box)return;box.innerHTML=worldTimeZones().map(z=>`<div class="worldRow"><b>${esc(z[0])}</b><strong>${esc(zoneTime(z[1]))}</strong><span>${esc(z[2])}</span><span>${esc(z[1])}</span></div>`).join('')}
function bindStatusMenus(){document.addEventListener('click',e=>{let btn=e.target.closest('[data-status-menu-toggle]');if(btn){let key=btn.getAttribute('data-status-menu-toggle');let menu=document.querySelector('[data-status-menu="'+key+'"]');document.querySelectorAll('.status-menu.show').forEach(m=>{if(m!==menu)m.classList.remove('show')});if(menu)menu.classList.toggle('show');e.stopPropagation();return}if(!e.target.closest('.status-dropdown'))document.querySelectorAll('.status-menu.show').forEach(m=>m.classList.remove('show'))});document.addEventListener('keydown',e=>{if(e.key==='Escape'){document.querySelectorAll('.status-menu.show').forEach(m=>m.classList.remove('show'));$('#noticePanel')?.classList.remove('show')}})}
async function load(opts={}){if(opts&&opts.type)opts={};let silent=!!opts.silent;try{if(!silent)$('#syncState').textContent='同步中';let fresh=await api('list',{date:state.date,q:state.search,personal_people_ids:state.peopleFilter.personal,dispatch_people_ids:state.peopleFilter.dispatch});mergeLocalCellEdits(fresh);state.data=fresh;state.me=fresh.me;if(!silent)prepareDailyFirstOpenMarks();if(fresh.version)state.syncVersion=String(fresh.version);if(!silent||!isTableEditing()){if(silent&&!opts.jumpToday)renderAllPreserveScroll();else renderAll();forceRecentCreateMarks();state.pendingRender=false;$('#syncState').textContent=(silent?'后台已更新 ':'已同步 ')+new Date().toLocaleTimeString('zh-CN',{hour12:false});if(state.pendingHighlightScroll)scrollToHighlight(state.pendingHighlightScroll);else if(opts.jumpToday)scrollToTodayTasks()}else{state.pendingRender=true;renderMetaOnly();$('#syncState').textContent='正在编辑，后台更新已暂存'}if(!silent)await dailyAcceptNotice()}catch(e){if(!silent){toast(e.message);$('#syncState').textContent='同步失败'}}}
function scrollToTodayTasks(){if(state.date!==today())return;requestAnimationFrame(()=>setTimeout(()=>{let target=document.querySelector('[data-today-task]')||document.querySelector('[data-table-section="dispatch"]')||document.querySelector('[data-table-section="personal"]');if(!target)return;target.scrollIntoView({behavior:'smooth',block:'start'});let wrap=target.closest?.('.tableWrap')||target.querySelector?.('.tableWrap');if(wrap)wrap.scrollLeft=0},80))}
function highlightKey(r){return r?.is_group?'g'+String(r.group_id||''):String(r?.id||'')}
function markRecentCreated(result,payload={}){let key=result?.group_id?('g'+result.group_id):(result?.id?String(result.id):''),until=Date.now()+20000;state.recentCreateFallback={until,title:String(payload.title||'').trim(),task_date:String(payload.task_date||state.date||''),created_by:String(state.me?.id||'')};if(key){state.recentCreated[key]=until;state.pendingHighlightScroll=key}clearTimeout(state.saveTimers.recent_created);state.saveTimers.recent_created=setTimeout(()=>{state.recentCreated={};state.recentCreateFallback=null;renderRowsOnly()},20500)}
function applyRecentCreateInline(el){if(!el)return;el.classList.add('recentCreate');el.style.removeProperty('background');el.style.removeProperty('color');el.querySelectorAll?.('td').forEach(td=>{td.style.removeProperty('background');td.style.removeProperty('color')})}
function forceRecentCreateMarks(){allVisibleRows().forEach(r=>{let key=highlightKey(r);if(!key||rowHighlightClass(r)!=='recentCreate')return;document.querySelectorAll(`[data-task-row="${escSelector(key)}"],[data-mobile-task="${escSelector(key)}"]`).forEach(applyRecentCreateInline)})}
function isRecentCreateFallback(r,now){let f=state.recentCreateFallback;if(!f||Number(f.until||0)<=now)return false;if(f.created_by&&String(r?.created_by||'')!==f.created_by)return false;if(f.task_date&&String(r?.task_date||'')!==f.task_date)return false;if(f.title&&String(r?.title||'').trim()!==f.title)return false;return true}
function isRecentCreatedByServerTime(r,now){if(String(r?.created_by||'')!==String(state.me?.id||''))return false;let s=String(r?.created_at||'').trim();if(!s)return false;let t=Date.parse(s.replace(' ','T'));return Number.isFinite(t)&&now-t>=-30000&&now-t<=20000}
function rowHighlightClass(r){let status=String(r?.status||'');if(status==='done'||status==='cancelled')return '';let key=highlightKey(r),now=Date.now();if(Number(r?.highlight_recent_create||0)||Number(r?.just_created||0)||(key&&Number(state.recentCreated[key]||0)>now)||isRecentCreateFallback(r,now)||isRecentCreatedByServerTime(r,now))return 'recentCreate';if(key&&Number(state.firstOpenMarked[key]||0)>now)return 'firstOpenMark';return ''}
function allVisibleRows(){return [...(state.data?.dispatch||[]),...(state.data?.personal||[]),...(state.data?.done||[])]}
function isFirstOpenCandidate(r){let d=today(),status=String(r.status||'');if(status==='done'||status==='cancelled')return false;return status==='pending_accept'||Number(r.is_read||1)===0||String(r.created_at||'').slice(0,10)===d||String(r.task_date||'')===d}
function prepareDailyFirstOpenMarks(){if(state.date!==today()||!state.me?.id)return;let key='dispatch_first_open_'+state.me.id+'_'+today();if(localStorage.getItem(key)==='1')return;let rows=allVisibleRows().filter(isFirstOpenCandidate);if(!rows.length){localStorage.setItem(key,'1');return}let until=Date.now()+20000;rows.forEach(r=>{let k=highlightKey(r);if(k)state.firstOpenMarked[k]=until});localStorage.setItem(key,'1');let first=rows.find(r=>String(r.status||'')==='pending_accept')||rows[0];state.pendingHighlightScroll=highlightKey(first);toast('已标出今日新增 / 待接收待办');setTimeout(()=>{state.firstOpenMarked={};renderRowsOnly()},20500)}
function escSelector(v){return window.CSS&&CSS.escape?CSS.escape(String(v)):String(v).replace(/"/g,'\\"')}
function scrollToHighlight(key){state.pendingHighlightScroll='';if(!key)return;requestAnimationFrame(()=>setTimeout(()=>{let escaped=escSelector(key);let sel=`[data-task-row="${escaped}"],[data-mobile-task="${escaped}"]`;let target=document.querySelector(sel)||document.querySelector('.recentCreate,.firstOpenMark');if(!target)return;if(Number(state.recentCreated[String(key)]||0)>Date.now())target.classList.add('recentCreate');target.scrollIntoView({behavior:'smooth',block:'center'});let wrap=target.closest?.('.tableWrap');if(wrap)wrap.scrollLeft=0},90))}
function startSyncTicker(){if(state.ticker)return;try{let blob=new Blob(['setInterval(function(){postMessage(Date.now())},1000)'],{type:'text/javascript'}),url=URL.createObjectURL(blob);state.ticker=new Worker(url);state.ticker.onmessage=backgroundTick}catch(e){setInterval(backgroundTick,1000)}backgroundTick()}
function backgroundTick(){updateStatusClock();if(document.hidden)return;let now=Date.now();if(now-state.lastVersionCheck>2000){state.lastVersionCheck=now;checkSyncVersion()}if(now-state.lastSilentSync>30000){state.lastSilentSync=now;load({silent:true})}if(now-state.lastNoticeSync>60000){state.lastNoticeSync=now;loadNotifications()}if(now-state.lastOnlineSync>30000){state.lastOnlineSync=now;loadOnlineStatus()}}
async function checkSyncVersion(){if(state.versionCheckRunning)return;state.versionCheckRunning=true;try{let v=await api('sync_version');let next=String(v.version||'');if(!next)return;if(!state.syncVersion){state.syncVersion=next;return}if(next!==state.syncVersion){state.syncVersion=next;state.lastSilentSync=Date.now();await load({silent:true})}}catch(e){}finally{state.versionCheckRunning=false}}
function resumeSync(){updateStatusClock();state.lastSilentSync=Date.now();state.lastOnlineSync=Date.now();load({silent:true});loadNotifications();loadOnlineStatus()}
function sendDispatchOnlineLeave(){try{let body=new FormData();body.set('action','online_leave');if(navigator.sendBeacon){navigator.sendBeacon(API,body);return}}catch(e){}api('online_leave').catch(()=>{})}
function isTableEditing(){let a=document.activeElement;return !!(a&&a.closest&&a.closest('.tableWrap')&&(a.matches('input,select,textarea,[contenteditable="true"]')||a.closest('[contenteditable="true"]')))}
function unreadDispatchRows(){return (state.data?.unread_dispatch||[]).filter(r=>!Number(r.is_read||0))}
function dispatchMessageCount(){return Number(state.data?.notifications?.pending_count||state.data?.notifications?.counts?.pending_all||0)}
function updateDispatchMessageMeta(){let count=dispatchMessageCount();$('#notifyCount').textContent=String(count);$('#notifyBtn').classList.toggle('danger',count>0);renderNotices(state.data?.notifications?.items||[])}
function renderMetaOnly(){if(!state.data)return;$('#personalCount').textContent=state.data.personal.length+' 条';$('#dispatchCount').textContent=state.data.dispatch.length+' 条';updateDispatchMessageMeta()}
function renderAll(){renderFilters('personal');renderFilters('dispatch');renderRowsOnly();updateDispatchMessageMeta();renderAccept()}
function captureScrollState(){return {windowX:window.scrollX||0,windowY:window.scrollY||0,wraps:$all('.tableWrap').map((el,i)=>({i,left:el.scrollLeft||0,top:el.scrollTop||0}))}}
function restoreScrollState(s){if(!s)return;requestAnimationFrame(()=>{s.wraps.forEach(w=>{let el=$all('.tableWrap')[w.i];if(el){el.scrollLeft=w.left;el.scrollTop=w.top}});window.scrollTo(s.windowX,s.windowY)})}
function renderAllPreserveScroll(){let s=captureScrollState();renderAll();restoreScrollState(s)}
function renderRowsOnly(){renderFocusBar();let personalDone=doneRowsFor('personal'),dispatchDone=doneRowsFor('dispatch');let personal=filterTasks('personal',state.data.personal||[]).concat(filterTasks('personal',personalDone)),dispatch=filterTasks('dispatch',state.data.dispatch||[]).concat(filterTasks('dispatch',dispatchDone));renderTable('personal',personal);renderTable('dispatch',dispatch);renderTable('done',[]);renderMobileTasks('personal',personal);renderMobileTasks('dispatch',dispatch);renderMobileSummary(personal,dispatch);pruneSelectedTasks();renderBatchBar();$('#personalCount').textContent=personal.length+'/'+((state.data.personal||[]).length+personalDone.length)+' 条';$('#dispatchCount').textContent=dispatch.length+'/'+((state.data.dispatch||[]).length+dispatchDone.length)+' 条'}
function taskById(id){id=String(id);let pools=[state.data?.personal||[],state.data?.dispatch||[],state.data?.done||[]];for(const rows of pools){for(const r of rows){if(String(r.id)===id)return r;if(r.children){let c=r.children.find(x=>String(x.id)===id);if(c)return c}}}return null}
function taskVersion(id){return taskById(id)?.updated_at||''}
function updateTaskVersion(id,updatedAt){if(!updatedAt)return;let t=taskById(id);if(t)t.updated_at=updatedAt;if(state.currentDetail?.task&&String(state.currentDetail.task.id)===String(id))state.currentDetail.task.updated_at=updatedAt}
function selectedTaskIds(){return Array.from(state.selectedTasks||[]).filter(id=>taskById(id)&&!String(id).startsWith('g'))}
function toggleBatchSelect(id,on){id=String(id||'');if(!id)return;if(on)state.selectedTasks.add(id);else state.selectedTasks.delete(id);renderBatchBar()}
function clearBatchSelection(){state.selectedTasks.clear();document.querySelectorAll('[data-batch-select]').forEach(cb=>cb.checked=false);renderBatchBar()}
function pruneSelectedTasks(){let ids=new Set([...(state.data?.personal||[]),(state.data?.dispatch||[]),(state.data?.done||[])].flatMap(r=>r.children?[r,...r.children]:[r]).map(r=>String(r.id)));Array.from(state.selectedTasks).forEach(id=>{if(!ids.has(String(id)))state.selectedTasks.delete(id)})}
function renderBatchBar(){let box=$('#batchBar');if(!box)return;let ids=selectedTaskIds();box.classList.toggle('show',ids.length>0);if(!ids.length){box.innerHTML='';return}box.innerHTML=`<strong>已选 ${ids.length} 条</strong><button class="btn mini" type="button" data-batch-action="assign">批量改负责人</button><button class="btn mini" type="button" data-batch-action="due">批量改截止日期</button><button class="btn mini" type="button" data-batch-action="priority">批量改优先级</button><button class="btn mini" type="button" data-batch-action="complete">批量完成</button><button class="btn mini" type="button" data-batch-action="urge">批量催办</button><button class="btn mini red" type="button" data-batch-action="delete">批量删除</button><button class="btn mini" type="button" data-batch-action="clear">取消选择</button>`}
async function handleBatchAction(action){let ids=selectedTaskIds();if(action==='clear')return clearBatchSelection();if(!ids.length)return toast('请先勾选待办');if(action==='assign')return openBatchAssignDialog(ids);if(action==='due'){let value=prompt('请输入截止日期，例如 2026-07-17 或 2026-07-17 18:00','');if(!value)return;return batchUpdateCell(ids,'due_at',value,'截止日期已更新')}if(action==='priority'){let value=prompt('优先级：today / urgent / important / normal','normal');if(!value)return;return batchUpdateCell(ids,'priority',value,'优先级已更新')}if(action==='complete')return batchComplete(ids);if(action==='urge')return batchUrge(ids);if(action==='delete')return batchDelete(ids)}
function openBatchAssignDialog(ids){$('#formTitle').textContent='批量改负责人';$('#formHint').textContent=`已选择 ${ids.length} 条待办，选择新的负责人后统一保存。`;$('#formTip').textContent='保存后会逐条调用现有权限校验和日志逻辑。';$('#formSave').style.display='inline-flex';$('#formSave').textContent='确认修改';$('#formBody').innerHTML=`<div class="panel"><h4>选择负责人</h4><label class="field"><span>新负责人</span><select id="batchAssignee">${userOptions('',true)}</select></label><p style="color:var(--muted);font-size:12px;margin:8px 0 0">只会修改已勾选的普通待办；多人组汇总行不会被批量修改。</p></div>`;$('#formSave').onclick=async()=>{let value=$('#batchAssignee')?.value;if(!value)return toast('请选择负责人');await batchUpdateCell(ids,'assigned_to',value,'负责人已更新');$('#formModal').close();$('#formSave').textContent='保存'};$('#formModal').showModal()}
async function batchUpdateCell(ids,field,value,msg){let ok=0,fail=0;for(const id of ids){try{let r=await api('update_cell',{task_id:id,field,value,client_updated_at:taskVersion(id)});updateTaskVersion(id,r.updated_at);ok++}catch(e){fail++}}toast(`${msg}：成功 ${ok}，失败 ${fail}`);clearBatchSelection();load({silent:true})}
async function batchComplete(ids){if(!confirm(`确认将 ${ids.length} 条待办标记为完成？`))return;let ok=0,fail=0;for(const id of ids){try{let r=await api('update_task',{id,status:'done',progress:100,client_updated_at:taskVersion(id)});updateTaskVersion(id,r.updated_at);ok++}catch(e){fail++}}toast(`批量完成：成功 ${ok}，失败 ${fail}`);clearBatchSelection();load()}
async function batchUrge(ids){let note=prompt('催办说明','请尽快处理这条派工');if(note===null)return;let ok=0,fail=0;for(const id of ids){try{await api('urge_task',{id,note});ok++}catch(e){fail++}}toast(`批量催办：成功 ${ok}，失败 ${fail}`);clearBatchSelection();load({silent:true})}
async function batchDelete(ids){if(!confirm(`确认删除选中的 ${ids.length} 条待办？此操作会写入日志。`))return;let ok=0,fail=0;for(const id of ids){try{await api('delete_task',{id});ok++}catch(e){fail++}}toast(`批量删除：成功 ${ok}，失败 ${fail}`);clearBatchSelection();load()}
function applyLocalCellValue(taskId,field,value){let t=taskById(taskId);if(!t||!field)return;if(field.startsWith('custom_')){t.custom_values=t.custom_values||{};t.custom_values[field.slice(7)]=value;return}if(field==='assigned_to'){t.assigned_to=value;let u=state.users.find(x=>String(x.id)===String(value));if(u)t.assignee_name=u.name}t[field]=value}
function cellEditKey(taskId,field){return String(taskId)+'_'+String(field)}
function rememberLocalCellEdit(taskId,field,value){if(!taskId||!field)return;state.localCellEdits[cellEditKey(taskId,field)]={taskId:String(taskId),field:String(field),value,ts:Date.now()}}
function clearLocalCellEdit(taskId,field,value){let key=cellEditKey(taskId,field),rec=state.localCellEdits[key];if(rec&&String(rec.value)===String(value))delete state.localCellEdits[key]}
function mergeLocalCellEdits(data){let edits=Object.values(state.localCellEdits||{}).filter(x=>Date.now()-Number(x.ts||0)<120000);state.localCellEdits={};edits.forEach(e=>state.localCellEdits[cellEditKey(e.taskId,e.field)]=e);if(!data||!edits.length)return;let old=state.data;state.data=data;edits.forEach(e=>applyLocalCellValue(e.taskId,e.field,e.value));state.data=old}
function cellStatusClass(status){return {pending:'cell-save-pending',saving:'cell-saving',saved:'cell-saved',error:'cell-error'}[status]||''}
function applyCellSaveStatusToElement(el,status){if(!el)return;el.classList.remove('cell-save-pending','cell-saving','cell-saved','cell-error');let cls=cellStatusClass(status);if(cls)el.classList.add(cls)}
function cellEditors(taskId,field){return $all('[data-cell-task][data-cell-field]').filter(el=>String(el.dataset.cellTask)===String(taskId)&&String(el.dataset.cellField)===String(field))}
function setCellSaveStatus(taskId,field,status,msg=''){let key=cellEditKey(taskId,field);if(status)state.cellSaveStatus[key]={status,msg,ts:Date.now()};else delete state.cellSaveStatus[key];cellEditors(taskId,field).forEach(el=>applyCellSaveStatusToElement(el,status));if(status==='saved')setTimeout(()=>{let rec=state.cellSaveStatus[key];if(rec&&rec.status==='saved'&&Date.now()-rec.ts>=1000){delete state.cellSaveStatus[key];cellEditors(taskId,field).forEach(el=>applyCellSaveStatusToElement(el,''))}},1200)}
function restoreCellSaveStatuses(root){root.querySelectorAll('[data-cell-task][data-cell-field]').forEach(el=>{let rec=state.cellSaveStatus[cellEditKey(el.dataset.cellTask,el.dataset.cellField)];if(rec)applyCellSaveStatusToElement(el,rec.status)})}
function renderMobileSummary(personal=[],dispatch=[]){let box=$('#mobileDispatchSummary');if(!box)return;let all=personal.concat(dispatch),overdue=all.filter(r=>r.due_state==='overdue').length,soon=all.filter(r=>r.due_state==='due_soon'||r.due_state==='due_today').length,unread=dispatchMessageCount(),accept=all.filter(r=>r.status==='pending_accept').length;box.innerHTML=`<article><span>今日任务</span><b>${all.length}</b></article><article><span>待接收</span><b>${accept}</b></article><article><span>将到期</span><b>${soon}</b></article><article><span>逾期</span><b>${overdue}</b></article>`}
function renderMobileTasks(type,rows=[]){let box=$('#'+type+'MobileCards');if(!box)return;let visible=rows.filter(r=>!r.is_group||r.children?.length),head='<div class="mobileTaskHead"><span>完成</span><span>优先级</span><span>标题 / 项目</span><span>截止</span><span>操作</span></div>';box.innerHTML=visible.length?head+visible.map(r=>mobileTaskCardHtml(r,type)).join(''):'<div class="mobileTaskEmpty">暂无任务</div>';bindMobileTaskCards(box)}
