function showStatusIcons(){return Number((state.colorPrefs||{}).show_status_icons??1)!==0}
function maxStatusIcons(){let p=state.colorPrefs||{};if(state.scope==='mobile')return Number(p.max_status_icons_mobile||3);if(state.scope==='mobile_landscape')return Number(p.max_status_icons_landscape||4);return Number(p.max_status_icons_desktop||4)}
function statusIconBadge(cls,icon,title,text=''){return `<span class="statusIconBadge ${esc(cls)}" title="${esc(title)}">${iconSvg(icon)}${text?`<span class="srOnly">${esc(text)}</span>`:''}</span>`}
function statusIconItems(r){let items=[];if(Number(r.step_count||0))items.push(['steps','steps',`步骤 ${Number(r.step_done_count||0)}/${Number(r.step_count||0)}`]);if(Number(r.image_count||0))items.push(['image','image','图片 '+Number(r.image_count||0)]);if(Number(r.attachment_count||0))items.push(['attachment','paperclip',(Number(r.valid_attachment_count||0)?'附件有效 ':'附件无效 ')+Number(r.attachment_count||0)]);if(Number(r.comment_count||0))items.push(['progress','message','进度记录 '+Number(r.comment_count||0)]);return items}
function statusDots(r){if(!showStatusIcons())return '';let s=String(r?.status||''),done=['done','cancelled'].includes(s),dc=dueClass(r),dots='';if(!done){if(dc)dots+=`<span class="statusDot ${esc(dc)}" title="${esc(r.due_label||'时效提醒')}"></span>`;else if(r?.due_at)dots+='<span class="statusDot normal" title="正常时效"></span>'}return dots?`<span class="statusDots">${dots}</span>`:''}
function statusIconTags(r){if(!showStatusIcons())return '';let items=statusIconItems(r),max=maxStatusIcons(),shown=items.slice(0,max),more=items.length-shown.length;if(more>0)shown.push(['more','more','还有 '+more+' 个状态','+'+more]);return shown.length?`<span class="statusIconStack">${shown.map(x=>x[3]?`<span class="statusIconBadge" title="${esc(x[2])}">${esc(x[3])}</span>`:statusIconBadge(x[0],x[1],x[2])).join('')}</span>`:''}
function taskDateOnly(v){return String(v||'').slice(0,10)}
function isTodayTask(r){let d=today();if(taskDateOnly(r.task_date)===d)return true;if(taskDateOnly(r.due_at)===d)return true;if(r.is_group&&Array.isArray(r.children))return r.children.some(isTodayTask);return state.date===d}
function renderCell(r,c){return `<td data-field="${esc(c.key)}"${recentCreateStyle(r)}>${renderEditableCell(r,c)}</td>`}
function groupCompleteButton(r){let childId=r.children?.[0]?.id||'',done=Number(r.done_count||0),total=Number(r.total_count||0),cls=total>0&&done>=total?' done':'';return `<button class="groupCompleteBtn${cls}" type="button" data-group-members="${esc(childId)}" title="查看多人派工成员状态">${done}/${total}</button>`}
function batchCheckbox(r){if(r.is_group)return '';let checked=state.selectedTasks.has(String(r.id))?'checked':'';return `<input class="batchSelect" type="checkbox" data-batch-select="${esc(r.id)}" ${checked} title="选择批量操作">`}
function mailTaskId(r){return Number(r?.mail_preview_task_id||0)}
function mailTaskButton(r,extra=''){let id=mailTaskId(r);return id>0?`<button class="mailBodyChip ${esc(extra)}" type="button" data-task-mail-body="${esc(id)}" title="预览 CRM 邮件正文">邮件正文</button>`:''}
function projectCellHtml(r,inner){let btn=mailTaskButton(r);return btn?`<div class="projectCellWrap">${btn}${inner}</div>`:inner}
function isConvertedPersonal(r){return ['personal','private'].includes(String(r?.task_type||''))&&['converted','hidden'].includes(String(r?.converted_status||''))}
function convertedSummary(r){let multi=Number(r.converted_group_id||0)>0,total=Number(r.converted_total_count||0),done=Number(r.converted_done_count||0),names=String(r.converted_assignee_names||'').trim();if(multi)return `已转为多人派工${total?` · ${done}/${total} 已完成`:''}${names?' · '+names:''}`;return `已转派给：${names||'接收人'}${r.converted_task_status_label?' · '+r.converted_task_status_label:''}`}
function convertedActions(r){let view=`<button class="btn mini" type="button" data-view-transfer="${esc(r.id)}">查看派工</button>`,restore=r.can_restore_transfer?`<button class="btn mini" type="button" data-restore-transfer="${esc(r.id)}">恢复个人待办</button>`:'';return `<span class="rowActions">${view}${restore}</span>`}
function renderEditableCell(r,c){
  let key=c.key;
  if(isConvertedPersonal(r)){
    if(key==='complete')return '';
    if(key==='title')return `<div class="titleCell lockedCell"><span class="lockedText">${esc(convertedSummary(r))}</span></div>`;
    if(key==='project')return `<span class="lockedText">${renderLinkedText(displayValue(r,'title')||'')}</span>`;
    if(key==='actions')return convertedActions(r);
  }
  if(key==='row_handle')return r.is_group?'':`<span class="row-drag" draggable="true" title="拖动排序">⋮⋮</span>`;
  if(key==='complete')return r.is_group?groupCompleteButton(r):`<span class="completeCellWrap">${batchCheckbox(r)}<button class="completeBtn ${r.status==='done'?'done':''}" data-done="${r.id}" data-done-status="${esc(r.status||'')}" title="${r.status==='done'?'取消完成，恢复进行中':'完成任务'}" aria-label="${r.status==='done'?'取消完成':'完成任务'}">${iconSvg('check')}</button></span>`;
  if(key==='actions'){
    let gid=r.is_group?r.group_id:'';
    if(isMobileLandscapeScope()){let detailId=r.is_group?(r.children[0]?.id||''):r.id;return `<div class="rowActions landscapeActions ${actionIconClass()}">${actionButton('action-detail','查看详情',`data-detail="${esc(detailId)}"`,actionIcon('detail'),'详情')}${r.is_group?actionButton('action-edit','修改多人派工',`data-edit-multi="${esc(gid)}" data-edit-source="${esc(detailId)}"`,actionIcon('edit'),'修改'):''}${actionButton('action-more','更多操作',`data-mobile-row-menu="${esc(detailId)}" data-source-id="${esc(r.id)}" data-status="${esc(r.status||'')}" data-can-transfer="${r.can_transfer?1:0}" data-can-restore-transfer="${r.can_restore_transfer?1:0}" data-can-urge="${r.can_urge&&!r.is_group?1:0}" data-can-delete="${r.can_delete?1:0}" data-is-group="${r.is_group?1:0}" data-group-id="${esc(gid)}"`,actionIcon('more'),'更多')}</div>`}
    return `<div class="rowActions ${actionIconClass()}">${actionButton('action-detail','查看详情',`data-detail="${esc(r.is_group?(r.children[0]?.id||''):r.id)}"`,actionIcon('detail'),'详情')}${r.is_group?actionButton('action-edit','修改多人派工',`data-edit-multi="${esc(gid)}" data-edit-source="${esc(r.children[0]?.id||'')}"`,actionIcon('edit'),'修改'):''}${r.can_transfer?transferButtonHtml(r.id):''}${r.can_urge&&!r.is_group?actionButton('action-urge','催办',`data-urge="${esc(r.id)}"`,actionIcon('urge'),'催办'):''}${r.can_delete?actionButton('action-danger','删除任务',`data-del="${esc(r.id)}" data-group="${esc(gid)}"`,actionIcon('delete'),'删除'):''}</div>`;
  }
  if(r.is_group){
    if(key==='title')return `<div class="titleCell lockedCell"><span class="lockedText">${renderLinkedText(displayValue(r,key))}</span>${statusDots(r)}${statusIconTags(r)}</div>`;
    if(key==='priority')return `<span class="pillCell">${prio(r.priority||'normal')}</span>`;
    if(key==='due_at')return `<span class="displayCell dateDisplay ${esc(dueClass(r))}" title="${esc((r.due_label? r.due_label+' · ':'')+(r.due_at||''))}">${esc(formatDue(r.due_at))}</span>`;
    if(key==='dispatch_mode')return `<span class="erpBadge people-multi">${iconSvg('users')}${esc(r.method_label||'多人')}</span>`;
    if(key==='assigned_to')return groupAssignees(r);
    if(key==='project')return projectCellHtml(r,`<span class="lockedText" title="${esc(taskTimeTitle(r))}">${renderLinkedText(displayValue(r,key))}</span>`);
    return esc(displayValue(r,key));
  }
  let value=displayValue(r,key);
  if(key==='priority')return `<select class="cell-input prioSelect prio-${esc(r.priority||'normal')}" data-cell-task="${r.id}" data-cell-field="priority">${['today','urgent','important','normal'].map(v=>`<option value="${v}" ${v===r.priority?'selected':''}>${prio(v)}</option>`).join('')}</select>`;
  if(key==='assigned_to')return `<span class="displayCell userDisplay erpBadge people-assignee" data-display-editor="assigned_to" data-task-id="${r.id}" data-value="${esc(r.assigned_to)}">${esc(r.assignee_name||'—')}</span>`;
  if(key==='due_at')return `<span class="displayCell dateDisplay ${esc(dueClass(r))}" data-display-editor="due_at" data-task-id="${r.id}" data-value="${esc((r.due_at||'').slice(0,10))}" title="${esc((r.due_label? r.due_label+' · ':'')+(r.due_at||''))}">${esc(formatDue(r.due_at))}</span>`;
  if(key==='dispatch_mode')return `<select class="cell-input methodSelect" data-cell-task="${r.id}" data-cell-field="dispatch_mode">${methodOptions(methodValue(r))}</select>`;
  if(key==='creator_name')return `<span class="erpBadge people-creator">${esc(r.creator_name||'-')}</span>`;
  if(key==='project')return projectCellHtml(r,`<div class="cell-edit multiline" contenteditable="true" title="${esc(taskTimeTitle(r))}" data-raw-value="${esc(value)}" data-cell-task="${r.id}" data-cell-field="project">${renderLinkedText(value)}</div>`);
  if(c.custom)return renderCustomCell(r,c,value);
  if(key==='title')return `<div class="titleCell"><div class="cell-edit" contenteditable="true" data-raw-value="${esc(value)}" data-cell-task="${r.id}" data-cell-field="title">${renderLinkedText(value)}</div>${statusDots(r)}${statusIconTags(r)}</div>`;
  return renderLinkedText(value);
}
function methodValue(r){if(r.task_type==='private')return 'private';if(r.task_type==='personal')return 'personal';return r.dispatch_mode||'single'}
function methodLabel(v){return {personal:'个人',private:'私人',single:'派工',dispatch:'派工',multi:'多人',group:'多人',planned:'计划',plan:'计划',recurring:'周期',cycle:'周期'}[v]||v||'派工'}
function methodOptions(selected){return [['personal','个人'],['private','私人'],['single','派工'],['multi','多人'],['plan','计划派工'],['recurring','周期派工']].map(v=>`<option value="${v[0]}" ${v[0]===selected?'selected':''}>${v[1]}</option>`).join('')}
function blankMethodOptions(type){let selected=type==='personal'?'personal':'single';return [['personal','个人'],['private','私人'],['single','派工']].map(v=>`<option value="${v[0]}" ${v[0]===selected?'selected':''}>${v[1]}</option>`).join('')}
function formatDue(v){if(!v)return '—';let s=String(v).trim(),m=s.match(/^(\d{4})[-\/](\d{1,2})[-\/](\d{1,2})/),pad=n=>String(n).padStart(2,'0');if(m)return pad(m[2])+'/'+pad(m[3]);m=s.match(/^(\d{1,2})[\/.-](\d{1,2})/);if(m)return pad(m[1])+'/'+pad(m[2]);let d=new Date(s.replace(' ','T'));if(isNaN(d))return s.replace(/^\d{4}[-\/]/,'');return pad(d.getMonth()+1)+'/'+pad(d.getDate())}
function monthDayParts(v){let s=formatDue(v);if(s==='—')return {m:'',d:''};let p=s.split('/');return {m:p[0]||'',d:p[1]||''}}
function monthDayPickerHtml(value='',attrs=''){let p=monthDayParts(value),months=[''].concat(Array.from({length:12},(_,i)=>String(i+1).padStart(2,'0'))),days=[''].concat(Array.from({length:31},(_,i)=>String(i+1).padStart(2,'0')));return `<span class="monthDayPicker" ${attrs}> <select data-md-month>${months.map(m=>`<option value="${m}" ${m===p.m?'selected':''}>${m||'月'}</option>`).join('')}</select><select data-md-day>${days.map(d=>`<option value="${d}" ${d===p.d?'selected':''}>${d||'日'}</option>`).join('')}</select></span>`}
function monthDayPickerValue(box){let m=box?.querySelector('[data-md-month]')?.value||'',d=box?.querySelector('[data-md-day]')?.value||'';return m&&d?normalizeBlankDue(m+'/'+d):''}
function dateParts(v){let d=v?new Date(String(v).replace(' ','T')):new Date();if(isNaN(d))d=new Date();return {y:d.getFullYear(),m:d.getMonth()+1,d:d.getDate()}}
function monthCalendarHtml(y,m,activeDay=0){let last=new Date(y,m,0).getDate(),first=new Date(y,m-1,1).getDay(),pad=n=>String(n).padStart(2,'0'),days='日一二三四五六'.split('').map(x=>`<small>${x}</small>`).join('');for(let i=0;i<first;i++)days+='<span></span>';for(let d=1;d<=last;d++)days+=`<button class="monthCalendarDay ${d===activeDay?'active':''}" type="button" data-cal-day="${d}">${d}</button>`;return `<div class="monthCalendarHead"><button type="button" data-cal-prev>‹</button><div class="monthCalendarTitle">${m}月</div><button type="button" data-cal-next>›</button></div><div class="monthCalendarGrid">${days}</div>`}
function placeMonthCalendar(pop,anchor){let r=anchor.getBoundingClientRect(),vw=window.visualViewport?.width||window.innerWidth,vh=window.visualViewport?.height||window.innerHeight,ox=window.visualViewport?.offsetLeft||0,oy=window.visualViewport?.offsetTop||0,w=pop.offsetWidth||184,h=pop.offsetHeight||220,left=Math.min(ox+vw-w-8,Math.max(ox+8,r.left+ox)),top=r.bottom+oy+4;if(top+h>oy+vh-8)top=Math.max(oy+8,r.top+oy-h-4);pop.style.left=left+'px';pop.style.top=top+'px'}
function openMonthCalendar(el,taskId,value){closeMonthCalendars();let p=dateParts(value),pop=document.createElement('div');pop.className='monthCalendar';pop.dataset.year=p.y;pop.dataset.month=p.m;pop.dataset.activeDay=p.d;function render(){pop.innerHTML=monthCalendarHtml(Number(pop.dataset.year),Number(pop.dataset.month),Number(pop.dataset.activeDay));placeMonthCalendar(pop,el)}function move(delta){let y=Number(pop.dataset.year),m=Number(pop.dataset.month)+delta;if(m<1){m=12;y--}if(m>12){m=1;y++}pop.dataset.year=y;pop.dataset.month=m;pop.dataset.activeDay='0';render()}render();document.body.appendChild(pop);placeMonthCalendar(pop,el);pop.addEventListener('click',e=>{if(e.target.closest('[data-cal-prev]'))return move(-1);if(e.target.closest('[data-cal-next]'))return move(1);let day=e.target.closest('[data-cal-day]');if(day){let y=Number(pop.dataset.year),m=String(pop.dataset.month).padStart(2,'0'),d=String(day.dataset.calDay).padStart(2,'0');saveCell(taskId,'due_at',`${y}-${m}-${d}`).then(ok=>{if(ok)load({silent:true})});closeMonthCalendars()}});setTimeout(()=>document.addEventListener('mousedown',monthCalendarOutsideClose),0)}
function openNewRowMonthCalendar(el){closeMonthCalendars();let rowKey=el.dataset.newRowKey,p=dateParts(),pop=document.createElement('div');pop.className='monthCalendar';pop.dataset.year=p.y;pop.dataset.month=p.m;pop.dataset.activeDay=p.d;function render(){pop.innerHTML=monthCalendarHtml(Number(pop.dataset.year),Number(pop.dataset.month),Number(pop.dataset.activeDay));placeMonthCalendar(pop,el)}function move(delta){let y=Number(pop.dataset.year),m=Number(pop.dataset.month)+delta;if(m<1){m=12;y--}if(m>12){m=1;y++}pop.dataset.year=y;pop.dataset.month=m;pop.dataset.activeDay='0';render()}render();document.body.appendChild(pop);placeMonthCalendar(pop,el);pop.addEventListener('click',e=>{if(e.target.closest('[data-cal-prev]'))return move(-1);if(e.target.closest('[data-cal-next]'))return move(1);let day=e.target.closest('[data-cal-day]');if(day){let y=Number(pop.dataset.year),m=String(pop.dataset.month).padStart(2,'0'),d=String(day.dataset.calDay).padStart(2,'0'),v=`${y}-${m}-${d}`;el.textContent=m+'/'+d;debounceCreateRow(rowKey,el.dataset.newType,el.dataset.newField,v);closeMonthCalendars()}});setTimeout(()=>document.addEventListener('mousedown',monthCalendarOutsideClose),0)}
function monthCalendarOutsideClose(e){if(!e.target.closest('.monthCalendar')&&!e.target.closest('[data-display-editor="due_at"]')&&!e.target.closest('[data-new-due-picker]'))closeMonthCalendars()}
function closeMonthCalendars(){document.removeEventListener('mousedown',monthCalendarOutsideClose);document.querySelectorAll('.monthCalendar').forEach(x=>x.remove())}
function taskTimeTitle(r){return `创建时间：${r.created_at||'—'}\n最后修改时间：${r.updated_at||'—'}`}
function normalizeBlankDue(v){let s=String(v||'').trim();if(!s)return '';if(/^\d{4}-\d{2}-\d{2}$/.test(s))return s;let m=s.match(/^(\d{1,2})[\/.-](\d{1,2})$/);if(!m)return s;let y=new Date().getFullYear(),mm=String(Math.max(1,Math.min(12,Number(m[1])))).padStart(2,'0'),dd=String(Math.max(1,Math.min(31,Number(m[2])))).padStart(2,'0');return y+'-'+mm+'-'+dd}
function renderLinkedText(text){let s=String(text??''),out='',plain='',last=0,chips=[],re=/(^|[\s，。；;、])@(时间|日期|客户|customer|邮件|mail|email|命名|naming|BOM|bom|报价|quote|PLM|plm|快照|snapshot|datasheet|资料|material|派工|dispatch|商机|opportunity)(?:\s*[:：#-]?\s*([A-Za-z0-9][A-Za-z0-9._\/-]{1,60}))?/g;for(let m;m=re.exec(s);){let prefix=m[1]||'',start=m.index+prefix.length,seg=s.slice(last,start);out+=esc(seg);plain+=seg;let raw=m[0].slice(prefix.length),kind=m[2],code=m[3]||'';if(kind==='时间'||kind==='日期'){out+=`<span class="linkToken timeToken" contenteditable="false" title="${kind==='时间'?'当前时间':'当前日期'}">${esc(kind==='时间'?currentTimeText():currentDateText())}</span><span class="ref-chip-edit-tail">\u200B</span>`}else if(code){chips.push({system:linkSystemKey(kind),code,raw})}else{out+=esc(raw);plain+=raw}last=re.lastIndex}out+=esc(s.slice(last));plain+=s.slice(last);if(!chips.length)return out;let clean=plain.replace(/\s+/g,' ').trim(),allChips=chips.map(c=>renderRefChip(c)).join('');if(!clean)return allChips+'<span class="ref-chip-edit-tail">\u200B</span>';return `<span class="ref-chip-list" contenteditable="false">${allChips}</span><span class="ref-chip-edit-tail">\u200B</span><span class="ref-chip-text">${esc(clean)}</span>`}
function renderRefChip(c,insidePopover=false){let meta=linkSystemMeta(c.system),code=String(c.code||'').trim(),title=`${meta.label}：${code}\n${meta.tip}`;return `<span class="linkToken ref-chip ref-chip-${esc(meta.cls)} is-clickable" contenteditable="false" data-linked-preview="1" data-linked-system="${esc(c.system)}" data-linked-code="${esc(code)}" data-linked-raw="${esc(c.raw||'')}" title="${esc(title)}"><span class="ref-chip-bar"></span><span class="ref-chip-type">${esc(meta.prefix)}</span><span class="ref-chip-code">${esc(code)}</span></span>`}
function linkSystemMeta(system){return {customer:{label:'客户',prefix:'@客户',cls:'customer',tip:'点击查看客户资料'},mail:{label:'邮件',prefix:'@邮件',cls:'mail',tip:'点击查看近三天客户邮件'},naming:{label:'命名',prefix:'@命名',cls:'naming',tip:'点击查看型号命名档案'},bom:{label:'BOM',prefix:'@BOM',cls:'bom',tip:'点击查看 BOM 明细'},quote:{label:'报价',prefix:'@报价',cls:'quote',tip:'点击查看报价详情'},plm:{label:'PLM',prefix:'@PLM',cls:'plm',tip:'点击查看 PLM 项目'},snapshot:{label:'快照',prefix:'@快照',cls:'snapshot',tip:'点击查看快照预览'},material:{label:'资料',prefix:'@资料',cls:'material',tip:'点击查看资料包详情'},dispatch:{label:'派工',prefix:'@派工',cls:'dispatch',tip:'点击查看派工详情'},opportunity:{label:'商机',prefix:'@商机',cls:'opportunity',tip:'点击查看商机详情'}}[system]||{label:system,prefix:'@'+system,cls:'dispatch',tip:'接口待接入'}}
function currentDateText(){let d=new Date(),pad=n=>String(n).padStart(2,'0');return d.getFullYear()+'-'+pad(d.getMonth()+1)+'-'+pad(d.getDate())}
function currentTimeText(){let d=new Date(),pad=n=>String(n).padStart(2,'0');return pad(d.getHours())+':'+pad(d.getMinutes())}
function linkSystemKey(s){s=String(s||'').toLowerCase();if(s==='客户'||s==='customer')return 'customer';if(s==='邮件'||s==='mail'||s==='email')return 'mail';if(s==='命名'||s==='naming')return 'naming';if(s==='报价'||s==='quote')return 'quote';if(s==='plm')return 'plm';if(s==='快照'||s==='snapshot'||s==='datasheet')return 'snapshot';if(s==='资料'||s==='material')return 'material';if(s==='派工'||s==='dispatch')return 'dispatch';if(s==='商机'||s==='opportunity')return 'opportunity';return 'bom'}
function renderCustomCell(r,c,value){let field=esc(c.key);if(c.type==='number')return `<input class="cell-input" type="number" value="${esc(value)}" data-cell-task="${r.id}" data-cell-field="${field}">`;if(c.type==='date')return `<input class="cell-input" type="date" value="${esc(String(value).slice(0,10))}" data-cell-task="${r.id}" data-cell-field="${field}">`;if(c.type==='datetime')return `<input class="cell-input" type="datetime-local" value="${esc(String(value).replace(' ','T').slice(0,16))}" data-cell-task="${r.id}" data-cell-field="${field}">`;if(c.type==='user')return `<select class="cell-input" data-cell-task="${r.id}" data-cell-field="${field}">${userOptions(value)}</select>`;if(c.type==='select')return `<select class="cell-input" data-cell-task="${r.id}" data-cell-field="${field}">${(c.options||[]).map(v=>`<option value="${esc(v)}" ${String(v)===String(value)?'selected':''}>${esc(v)}</option>`).join('')}</select>`;return `<div class="cell-edit ${c.type==='textarea'?'multiline':''}" contenteditable="true" data-raw-value="${esc(value)}" data-cell-task="${r.id}" data-cell-field="${field}">${renderLinkedText(value)}</div>`}
function displayValue(r,key){if(key&&key.startsWith('custom_'))return (r.custom_values||{})[key.slice(7)]||'';if(key==='assigned_to')return r.assignee_name||'';if(key==='dispatch_mode')return r.method_label||'';return r[key]??''}
function bindEditableCells(root){root.querySelectorAll('td').forEach(td=>td.addEventListener('click',e=>{let more=e.target.closest('[data-ref-more]');if(more){toggleRefChipPopover(more);e.preventDefault();e.stopPropagation();return}let token=e.target.closest('[data-linked-preview]');if(token){openLinkedPreview(token.dataset.linkedSystem,token.dataset.linkedCode);e.preventDefault();e.stopPropagation();return}let newDue=e.target.closest('[data-new-due-picker]');if(newDue){openNewRowMonthCalendar(newDue);e.preventDefault();e.stopPropagation();return}let display=e.target.closest('[data-display-editor]');if(display){activateDisplayEditor(display);e.preventDefault();e.stopPropagation();return}if(e.target.closest('button,.row-drag'))return;let el=td.querySelector('[contenteditable="true"],input,select');if(el)focusCellEditor(el,e)}));root.querySelectorAll('[data-ref-more]').forEach(more=>{more.addEventListener('mousedown',e=>{e.preventDefault();e.stopPropagation()});more.addEventListener('click',e=>{toggleRefChipPopover(more);e.preventDefault();e.stopPropagation()})});root.querySelectorAll('[data-linked-preview]').forEach(token=>{token.addEventListener('mousedown',e=>{e.preventDefault();e.stopPropagation()});token.addEventListener('click',e=>{openLinkedPreview(token.dataset.linkedSystem,token.dataset.linkedCode);e.preventDefault();e.stopPropagation()})});root.querySelectorAll('[data-display-editor]').forEach(el=>el.addEventListener('click',e=>{activateDisplayEditor(el);e.preventDefault();e.stopPropagation()}));root.querySelectorAll('[data-new-due-picker]').forEach(el=>el.addEventListener('click',e=>{openNewRowMonthCalendar(el);e.preventDefault();e.stopPropagation()}));root.querySelectorAll('[data-cell-task]').forEach(el=>{let eventName=el.tagName==='SELECT'||el.tagName==='INPUT'?'change':'input';if(el.isContentEditable)el.addEventListener('keydown',handleEditableEnter);el.addEventListener(eventName,()=>handleExistingCellInput(el));el.addEventListener('blur',()=>handleExistingCellBlur(el))});root.querySelectorAll('[data-new-row-key]:not([data-new-due-picker])').forEach(el=>{let eventName=el.tagName==='SELECT'||el.tagName==='INPUT'?'change':'input';if(el.isContentEditable)el.addEventListener('keydown',handleEditableEnter);el.addEventListener(eventName,()=>debounceCreateRow(el.dataset.newRowKey,el.dataset.newType,el.dataset.newField,el.tagName==='SELECT'||el.tagName==='INPUT'?el.value:editableText(el)));el.addEventListener('blur',()=>handleNewRowBlur(el));el.addEventListener('focus',()=>cancelNewRowCreateTimer(el.dataset.newRowKey))});root.querySelectorAll('[data-task-row]').forEach(row=>{row.addEventListener('dragstart',e=>{if(!e.target.closest('.row-drag')){e.preventDefault();return}state.dragRow=row});row.addEventListener('dragover',e=>{if(!state.dragRow)return;e.preventDefault();let target=e.currentTarget;if(state.dragRow!==target){let box=target.getBoundingClientRect();target.parentNode.insertBefore(state.dragRow,e.clientY<box.top+box.height/2?target:target.nextSibling)}});row.addEventListener('drop',e=>{e.preventDefault();saveRowOrder(row.dataset.tableType)});row.addEventListener('dragend',()=>{state.dragRow=null})})}
function toggleRefChipPopover(more){let pop=more.parentElement?.querySelector('.ref-chip-popover');if(!pop)return;document.querySelectorAll('.ref-chip-popover:not([hidden])').forEach(p=>{if(p!==pop)p.hidden=true});let open=pop.hidden;pop.hidden=!open;if(open){let r=more.getBoundingClientRect(),w=Math.min(360,window.innerWidth-24),left=Math.min(Math.max(12,r.left),window.innerWidth-w-12),top=Math.min(r.bottom+6,window.innerHeight-90);pop.style.left=left+'px';pop.style.top=top+'px';pop.style.maxWidth=w+'px'}}
function editableText(el){return String(el.textContent||'').replace(/\u200B/g,'').replace(/\u00a0/g,' ')}
function plainEditValue(el){return String(el.dataset.rawValue!==undefined&&!el.dataset.plainEditing?el.dataset.rawValue:editableText(el))}
function enterPlainEdit(el){if(!el?.isContentEditable||el.dataset.plainEditing)return false;let raw=el.dataset.rawValue!==undefined?el.dataset.rawValue:editableText(el);el.textContent=raw;el.dataset.plainEditing='1';return true}
function handleExistingCellInput(el){let value=el.tagName==='SELECT'||el.tagName==='INPUT'?el.value:editableText(el),taskId=el.dataset.cellTask,field=el.dataset.cellField;if(el.dataset.rawValue!==undefined)el.dataset.rawValue=value;setCellSaveStatus(taskId,field,'pending');$('#syncState').textContent='正在编辑，等待保存';rememberLocalCellEdit(taskId,field,value);applyLocalCellValue(taskId,field,value);debounceSaveCell(taskId,field,value);if(['title','project'].includes(field))scheduleEmptyDeleteForRow(el.closest('[data-task-row]'))}
function scheduleEmptyDeleteScan(root){root.querySelectorAll('tr[data-task-row]').forEach(scheduleEmptyDeleteForRow)}
function emptyDeleteCellText(row,field){let el=row?.querySelector(`td[data-field="${field}"] [data-cell-field="${field}"]`);if(!el)return '';return String(el.tagName==='INPUT'||el.tagName==='SELECT'?el.value:plainEditValue(el)).replace(/\u00a0/g,' ').trim()}
function emptyDeleteRowIsBlank(row){return !!(row&&row.querySelector('[data-cell-field="title"]')&&row.querySelector('[data-cell-field="project"]')&&!emptyDeleteCellText(row,'title')&&!emptyDeleteCellText(row,'project'))}
function cancelEmptyDeleteTimer(id){if(state.emptyDeleteTimers[id]){clearTimeout(state.emptyDeleteTimers[id]);delete state.emptyDeleteTimers[id]}}
function scheduleEmptyDeleteForRow(row){if(!row)return;let id=String(row.dataset.taskRow||'');if(!id||id.startsWith('g'))return;if(!emptyDeleteRowIsBlank(row)){cancelEmptyDeleteTimer(id);return}if(state.emptyDeleteTimers[id])return;state.emptyDeleteTimers[id]=setTimeout(async()=>{delete state.emptyDeleteTimers[id];let live=$all('tr[data-task-row]').find(r=>String(r.dataset.taskRow)===id);if(!emptyDeleteRowIsBlank(live))return;try{await api('delete_task',{id});toast('空待办已删除');load()}catch(e){toast(e.message)}},10000)}
function activateDisplayEditor(el){let field=el.dataset.displayEditor,taskId=el.dataset.taskId,value=el.dataset.value||'',editor;if(field==='due_at'){openMonthCalendar(el,taskId,value);return}else if(field==='assigned_to'){editor=document.createElement('select');editor.className='cell-input';editor.innerHTML=userOptions(value,false)}else{return}editor.dataset.cellTask=taskId;editor.dataset.cellField=field;el.replaceWith(editor);editor.focus();editor.addEventListener('change',()=>saveCell(taskId,field,editor.value).then(ok=>{if(ok)load({silent:true})}));editor.addEventListener('blur',()=>setTimeout(()=>{if(document.body.contains(editor)&&!state.cellSaveStatus[cellEditKey(taskId,field)])load({silent:true})},120))}
function handleExistingCellBlur(el){flushCellSave(el).finally(()=>flushPendingTableRender())}
function flushCellSave(el){let taskId=el.dataset.cellTask,field=el.dataset.cellField;if(!taskId||!field)return Promise.resolve();let key=taskId+'_'+field,value=el.tagName==='SELECT'||el.tagName==='INPUT'?el.value:editableText(el);clearTimeout(state.saveTimers[key]);delete state.saveTimers[key];setCellSaveStatus(taskId,field,'saving');rememberLocalCellEdit(taskId,field,value);applyLocalCellValue(taskId,field,value);return saveCell(taskId,field,value)}
function hasBlockingCellError(){return Object.values(state.cellSaveStatus||{}).some(x=>x&&x.status==='error')}
function flushPendingTableRender(){setTimeout(()=>{if(state.pendingRender&&!isTableEditing()){if(hasBlockingCellError()){ $('#syncState').textContent='有保存冲突，后台更新暂不覆盖';return}renderAllPreserveScroll();state.pendingRender=false;$('#syncState').textContent='已合并后台更新 '+new Date().toLocaleTimeString('zh-CN',{hour12:false})}},80)}
function focusCellEditor(el,e){let clickedInsideEditor=e&&el.contains(e.target),clickedToken=e&&e.target.closest&&e.target.closest('[contenteditable="false"],.ref-chip,.ref-chip-list'),changed=el.isContentEditable?enterPlainEdit(el):false;el.focus();if(!el.isContentEditable)return;if(clickedInsideEditor&&!clickedToken&&!changed)return;placeCaretFromPointer(el,e)}
function placeCaretFromPointer(el,e){let sel=window.getSelection();if(!sel)return;if(e&&Number.isFinite(e.clientX)&&Number.isFinite(e.clientY)){let range=null;if(document.caretRangeFromPoint)range=document.caretRangeFromPoint(e.clientX,e.clientY);else if(document.caretPositionFromPoint){let pos=document.caretPositionFromPoint(e.clientX,e.clientY);if(pos){range=document.createRange();range.setStart(pos.offsetNode,pos.offset);range.collapse(true)}}if(range&&el.contains(range.startContainer)){sel.removeAllRanges();sel.addRange(range);return}if(placeCaretByClosestTextOffset(el,e.clientX,e.clientY))return}let range=document.createRange();range.selectNodeContents(el);range.collapse(false);sel.removeAllRanges();sel.addRange(range)}
function textNodesOf(el){let out=[],w=document.createTreeWalker(el,NodeFilter.SHOW_TEXT);for(let n;n=w.nextNode();)out.push(n);return out}
function placeCaretByClosestTextOffset(el,x,y){let nodes=textNodesOf(el),sel=window.getSelection();if(!nodes.length||!sel)return false;let best=null;for(const node of nodes){let len=node.nodeValue.length;if(!len){let r=document.createRange();r.setStart(node,0);r.setEnd(node,0);let rect=r.getBoundingClientRect();let d=Math.hypot(rect.left-x,rect.top-y);if(!best||d<best.d)best={node,offset:0,d};continue}for(let i=0;i<=len;i++){let r=document.createRange();r.setStart(node,i);r.setEnd(node,i);let rects=r.getClientRects(),rect=rects[0]||r.getBoundingClientRect();if(!rect)continue;let cx=rect.left,cy=rect.top+rect.height/2,d=Math.hypot(cx-x,cy-y);if(!best||d<best.d)best={node,offset:i,d}}}if(!best)return false;let range=document.createRange();range.setStart(best.node,best.offset);range.collapse(true);sel.removeAllRanges();sel.addRange(range);return true}
function handleEditableEnter(e){if(e.key!=='Enter'||e.ctrlKey||e.metaKey||e.altKey)return;e.preventDefault();e.stopPropagation();insertEditableNewline(e.currentTarget)}
function insertEditableNewline(el){let sel=window.getSelection();if(!sel||!sel.rangeCount){document.execCommand('insertText',false,'\n');return}let range=sel.getRangeAt(0);range.deleteContents();let node=document.createTextNode('\n');range.insertNode(node);range.setStartAfter(node);range.setEndAfter(node);sel.removeAllRanges();sel.addRange(range);el.dispatchEvent(new InputEvent('input',{bubbles:true,inputType:'insertLineBreak',data:'\n'}))}
function debounceSaveCell(taskId,field,value){let key=taskId+'_'+field;clearTimeout(state.saveTimers[key]);state.saveTimers[key]=setTimeout(()=>saveCell(taskId,field,value),500)}
async function saveCell(taskId,field,value){try{setCellSaveStatus(taskId,field,'saving');rememberLocalCellEdit(taskId,field,value);applyLocalCellValue(taskId,field,value);let r=await api('update_cell',{task_id:taskId,field,value,client_updated_at:taskVersion(taskId)});updateTaskVersion(taskId,r.updated_at);clearLocalCellEdit(taskId,field,value);setCellSaveStatus(taskId,field,'saved');$('#syncState').textContent='已保存 '+new Date().toLocaleTimeString('zh-CN',{hour12:false});return true}catch(e){let msg=String(e.message||'保存失败'),conflict=msg.includes('已被别人更新');setCellSaveStatus(taskId,field,'error',msg);toast(conflict?'此单元格已被别人更新，当前输入未覆盖':'保存失败：'+msg);$('#syncState').textContent=conflict?'保存冲突，当前输入已保留':'保存失败';if(conflict)state.pendingRender=true;return false}}
function cancelNewRowCreateTimer(rowKey){clearTimeout(state.saveTimers['new_'+rowKey])}
function newRowHasFocus(rowKey){let row=document.querySelector(`tr[data-new-row="${rowKey}"]`),a=document.activeElement;return !!(row&&a&&row.contains(a))}
function debounceCreateRow(rowKey,type,field,value){let rec=state.newRows[rowKey]||{task_type:type,priority:'normal',task_date:state.date,assigned_to:state.me?.id||''};rec[field]=value;state.newRows[rowKey]=rec;cancelNewRowCreateTimer(rowKey);if(!newRowHasFocus(rowKey))state.saveTimers['new_'+rowKey]=setTimeout(()=>createInlineRow(rowKey),250)}
function handleNewRowBlur(el){flushPendingTableRender();let rowKey=el.dataset.newRowKey;setTimeout(()=>{if(!newRowHasFocus(rowKey))createInlineRow(rowKey)},120)}
async function createInlineRow(rowKey){let rec=state.newRows[rowKey];if(!rec||rec._saving||newRowHasFocus(rowKey))return;if(!String(rec.title||'').trim())return;let dueAt=normalizeBlankDue(rec.due_at);if(!dueAt){toast('派工待办必须填写截止时间');return}let method=rec.method||rec.task_type;let taskType=method==='private'?'private':(method==='personal'?'personal':'dispatch'),payload={task_type:taskType,title:rec.title,project:rec.project||'',priority:rec.priority||'normal',task_date:state.date,due_at:dueAt,assigned_to:rec.assigned_to||state.me?.id||''};rec._saving=true;try{let created=await api('create_task',payload);markRecentCreated(created,payload);delete state.newRows[rowKey];toast('已新增');load()}catch(e){rec._saving=false;toast(e.message)}}
async function saveRowOrder(type){let ids=$all(`tr[data-table-type="${type}"]`).map(r=>Number(r.dataset.taskRow)).filter(Boolean);await api('save_row_order',{table_type:type,task_ids:ids}).catch(()=>{});toast('行顺序已保存')}
async function openNoticeDetail(el){let nid=String(el?.dataset?.noticeId||''),tid=String(el?.dataset?.detail||'');if(nid&&/^\d+$/.test(nid))await api('mark_read',{id:nid}).catch(()=>{});if(nid.startsWith('task_'))await api('mark_task_read',{id:nid.replace('task_','')}).catch(()=>{});if(tid)openDetail(tid);else loadNotifications(false)}
async function openLinkedPreview(system,code){if(!system||!code)return;$('#linkPreviewTitle').textContent='联动预览 · '+linkSystemLabel(system)+' '+code;$('#linkPreviewHint').textContent='正在读取预览信息，不跳转页面。';$('#linkPreviewBody').innerHTML='<div class="previewEmpty">加载中...</div>';$('#linkPreviewModal').showModal();try{let d=await api('preview_link',{system,code});$('#linkPreviewTitle').textContent='联动预览 · '+escText(d.label||linkSystemLabel(system))+' '+escText(d.code||code);$('#linkPreviewHint').textContent=d.status==='connected'?'已读取到接入数据':'接口已预留，正式系统接入后显示完整详情';$('#linkPreviewBody').innerHTML=previewHtml(d)}catch(e){$('#linkPreviewBody').innerHTML='<div class="previewEmpty">预览失败：'+esc(e.message)+'</div>'}}
function linkSystemLabel(system){return {customer:'客户',mail:'邮件',naming:'命名',bom:'BOM',quote:'报价',plm:'PLM',snapshot:'快照',material:'资料',dispatch:'派工',opportunity:'商机'}[system]||system}
function escText(s){let div=document.createElement('div');div.innerHTML=esc(s);return div.textContent}
function previewHtml(d){let fields=(d.fields||[]).filter(f=>String(f.value??'').trim()!=='');let rows=fields.map(f=>`<b>${esc(f.label)}</b><span>${esc(f.value??'')}</span>`).join('');let media=(d.media||[]).filter(m=>m.url).map(m=>`<figure><img src="${esc(m.url)}" alt="${esc(m.label||'预览图')}" loading="lazy"><figcaption>${esc(m.label||'图片')}</figcaption></figure>`).join('');let mediaHtml=media?`<div class="previewMedia">${media}</div>`:'';let actions=(d.actions||[]).map(a=>String(a.hint||'').match(/^(https?:\/\/|[a-z_]+\.php|\?)/i)?`<a class="btn mini" href="${esc(a.hint)}" target="_blank" rel="noopener">${esc(a.label)}</a>`:`<button class="btn mini" type="button" disabled title="${esc(a.hint||'接口待接入')}">${esc(a.label)}</button>`).join('');let itemHtml=quotePreviewItemsHtml(d)+bomPreviewItemsHtml(d)+mailPreviewItemsHtml(d)+plmPreviewItemsHtml(d),panelCls=d.system==='plm'?'panel plmPreviewSummary':'panel';return `<div class="${panelCls}"><h4>${esc(d.label||'联动对象')} <span class="previewBadge">${esc(d.status_label||'待接入')}</span></h4>${mediaHtml}<div class="previewGrid"><b>系统</b><span>${esc(linkSystemLabel(d.system))}</span><b>编号</b><span>${esc(d.code)}</span>${rows}</div></div>${itemHtml}<div class="panel"><h4>可用动作</h4><div style="display:flex;gap:6px;flex-wrap:wrap">${actions||'<span class="previewEmpty">暂无动作</span>'}</div></div>${d.message?`<div class="previewEmpty">${esc(d.message)}</div>`:''}`}
function plmNodeTip(rows){return `<div class="plmNodeTip">${rows.filter(x=>String(x[1]??'').trim()!=='').map(x=>`<span><b>${esc(x[0])}：</b>${esc(x[1])}</span>`).join('')||'<span>暂无更多信息</span>'}</div>`}
function plmFlowNodeHtml(n){let detail=[['步骤',n.title],['状态',n.status],['负责人',n.owner||'未指定'],['计划',n.plan||'-'],['完成',n.done_at||'-'],['派工',n.dispatch||'未派工'],['说明',n.note||'']];return `<article class="plmNode ${esc(n.tone||'todo')}"><div class="plmNodeTop"><span class="plmNodeIndex">${String(n.index||'').padStart(2,'0')}</span><span class="plmNodeStatus">${esc(n.status||'-')}</span></div><div class="plmNodeTitle">${esc(n.title||'未命名步骤')}</div><div class="plmNodeMeta"><span>${esc(n.owner||'未指定')}</span><span>${esc(n.dispatch||'未派工')}</span></div>${plmNodeTip(detail)}</article>`}
function plmTestNodeHtml(n){let detail=[['测试',n.title],['类型',n.type||''],['状态',n.status],['结果',n.result],['日期',n.date||'-'],['测试人',n.operator||'-'],['资料',`图片 ${n.image_count||0} / 文件 ${n.file_count||0} / 报告 ${n.report_count||0}`],['结论',n.conclusion||'']];return `<article class="plmNode ${esc(n.tone||'todo')}"><div class="plmNodeTop"><span class="plmNodeIndex">${String(n.index||'').padStart(2,'0')}</span><span class="plmNodeStatus">${esc(n.result||n.status||'-')}</span></div><div class="plmNodeTitle">${esc(n.title||'测试项目')}</div><div class="plmNodeMeta"><span>${esc(n.status||'-')}</span><span>报告 ${Number(n.report_count||0)}</span></div>${plmNodeTip(detail)}</article>`}
function plmPreviewItemsHtml(d){let data=d.plm||{};if(d.system!=='plm'||!data)return '';let steps=Array.isArray(data.steps)?data.steps:[],tests=Array.isArray(data.tests)?data.tests:[],model=data.model||{},head=[model.model,model.name,model.version].filter(Boolean).join(' · ');return `<div class="panel plmPreviewBoard"><div class="plmPreviewHead"><h4>PLM 节点图</h4><small>${esc(head||'项目级预览')}，鼠标悬停节点查看详情</small></div><section><div class="plmPreviewHead"><h4>开发导航图</h4><small>${steps.length} 个节点</small></div>${steps.length?`<div class="plmNodeRail">${steps.map(plmFlowNodeHtml).join('')}</div>`:'<div class="plmPreviewEmpty">当前样品暂无开发流程节点。</div>'}</section><section><div class="plmPreviewHead"><h4>测试中心</h4><small>${tests.length} 个测试项目</small></div>${tests.length?`<div class="plmNodeRail">${tests.map(plmTestNodeHtml).join('')}</div>`:'<div class="plmPreviewEmpty">当前样品暂无测试项目。</div>'}</section></div>`}
function quotePreviewItemsHtml(d){let items=Array.isArray(d.items)?d.items:[];if(d.system!=='quote'||!items.length)return '';let price=!!Number(d.can_view_price||0);let head=`<tr><th>#</th><th>型号 / 产品</th><th>规格</th><th>数量</th>${price?'<th>单价</th><th>金额</th>':''}</tr>`;let body=items.map(it=>`<tr><td>${esc(it.index||'')}</td><td><b>${esc(it.model||'-')}</b><small>${esc(it.name||'')}</small></td><td>${esc([it.power,it.size,it.color,it.cct,it.cri,it.ip,it.spec].filter(Boolean).join(' / '))}</td><td class="num">${esc(it.qty||'')}</td>${price?`<td class="num">${esc(it.price||'')}</td><td class="num">${esc(it.amount||'')}</td>`:''}</tr>`).join('');return `<div class="panel"><h4>报价明细</h4><table class="quotePreviewTable">${head}${body}</table></div>`}
function bomPreviewItemsHtml(d){let items=Array.isArray(d.items)?d.items:[];if(d.system!=='bom'||!items.length)return '';let cost=!!Number(d.can_view_cost||0),supplier=!!Number(d.can_view_supplier||0),sum=d.summary||{};let summary=cost?`<div class="bomSummaryGrid"><article><span>币种</span><b>${esc(sum.currency||'-')}</b></article><article><span>物料成本</span><b>${esc(sum.material_cost||'0')}</b></article><article><span>人工/其它</span><b>${esc(sum.extra_cost||'0')}</b></article><article><span>总成本</span><b>${esc(sum.total_cost||'0')}</b></article></div>`:'';let head=`<tr><th>#</th><th>物料</th><th>规格</th><th>数量</th><th>表面/加工</th>${supplier?'<th>供应商</th>':''}${cost?'<th>单价</th><th>加工</th><th>金额</th>':''}</tr>`;let body=items.map(it=>`<tr><td>${esc(it.index||'')}</td><td><b>${esc(it.name||'-')}</b><small>${esc([it.category,it.model].filter(Boolean).join(' / '))}</small></td><td>${esc(it.spec||'')}</td><td class="num">${esc([it.qty,it.unit].filter(Boolean).join(' '))}</td><td>${esc(it.finish||'')}</td>${supplier?`<td>${esc(it.supplier||'')}</td>`:''}${cost?`<td class="num">${esc(it.price||'')}</td><td class="num">${esc(it.process||'')}</td><td class="num">${esc(it.amount||'')}</td>`:''}</tr>`).join('');return `<div class="panel"><h4>BOM 明细</h4>${summary}<div class="bomPreviewTableWrap"><table class="quotePreviewTable bomPreviewTable">${head}${body}</table></div></div>`}
