function combinedNotices(rows=[]){return (rows||[]).map(n=>Object.assign({},n,{id:String(n.id||''),event_type:n.event_type||n.type}))}
function isUpdateNotice(n){return String(n.type||'')==='urge'&&String(n.title||'')==='任务已更新'&&n.task_id}
function noticeGroupKey(n){return isUpdateNotice(n)?['update',n.task_id,n.type,n.title,Number(n.is_read||0)?'read':'unread'].join('_'):String(n.id||'')}
function mergeDisplayNotices(rows=[]){let map=new Map(),out=[];for(const n of rows){let key=noticeGroupKey(n);if(!map.has(key)){let copy=Object.assign({},n,{_merged_count:1,_merged_items:[n]});map.set(key,copy);out.push(copy);continue}let item=map.get(key);item._merged_count++;item._merged_items.push(n);if(Number(n.id||0)>Number(item.id||0)||String(n.created_at||'')>String(item.created_at||'')){Object.assign(item,n,{_merged_count:item._merged_count,_merged_items:item._merged_items})}}return out}
function noticeIsPending(n){return Number(n.action_required||0)===1&&!['handled','snoozed'].includes(String(n.status||''))}
function noticeMatchesFilter(n,filter){let e=String(n.event_type||n.type||''),pending=noticeIsPending(n);if(filter==='pending_all')return pending;if(filter==='new_dispatch')return pending&&e==='new_dispatch';if(filter==='due_today')return pending&&e==='due_today';if(filter==='overdue')return pending&&e==='overdue';if(filter==='confirm')return pending&&e==='completed_pending_confirm';if(filter==='urge')return pending&&e==='urge';if(filter==='blocked')return pending&&['task_blocked','delay_requested','task_returned'].includes(e);if(filter==='history')return !pending;if(filter==='activity')return !pending&&['task_updated','progress_added','attachment_added'].includes(e);return pending}
function noticeMatchesSearch(n){let q=String(state.noticeSearch||'').trim().toLowerCase();if(!q)return true;return [n.title,n.message,n.created_at,n.type,n.method_label,n.task_id].some(v=>String(v||'').toLowerCase().includes(q))}
function filteredNotices(rows=[]){let list=combinedNotices(rows),filter=state.noticeFilter||'unread',rules=normalizeNoticeRules(state.noticeRules);return list.filter(n=>(!rules.hide_read||!Number(n.is_read||0))&&(!rules.mute_done||String(n.type||'')!=='done')&&noticeMatchesFilter(n,filter)&&noticeMatchesSearch(n))}
