function renderNotices(rows=[]){let pending=Number(state.data?.notifications?.pending_count||state.data?.notifications?.counts?.pending_all||0),pendingRows=pending>0?mergeDisplayNotices((rows||[]).filter(noticeIsPending)):[],latest=pendingRows.slice(0,5),more=Math.max(0,pendingRows.length-latest.length),pendingBlock=latest.length?`<section class="dispatchNoticeSection"><div class="dispatchNoticeSectionTitle"><b>待处理事项</b><span>最近 ${latest.length} 条</span></div>${latest.map(n=>noticeRowHtml(n,true)).join('')}</section>`:`<section class="dispatchNoticeSection"><div class="dispatchNoticeEmpty"><b>暂无待处理事项</b><span>没有新派工、逾期、催办或待确认。</span></div></section>`;$('#noticeList').innerHTML=`<div class="noticeHead"><div><b>待处理提醒</b><small>只显示需要你处理的派工事项 · ${pending} 条</small></div><div class="noticeActions"><button class="btn mini" type="button" onclick="setNoticeFilter('history');openNoticeCenter()">历史记录</button><button class="btn mini primary" type="button" onclick="openNoticeCenter()">待处理中心</button></div></div><div class="noticeListCompact">${pendingBlock}</div><div class="noticeFooter"><span>${more?`还有 ${more} 条待处理`:'待处理必须完成动作后消失'}</span><button class="btn mini" type="button" onclick="openNoticeCenter()">查看更多</button></div>`}
